import{_ as t,o as a,c as o,a4 as s}from"./chunks/framework.DBZEZKAP.js";const h=JSON.parse('{"title":"Tool Catalog","description":"","frontmatter":{},"headers":[],"relativePath":"tools.md","filePath":"tools.md","lastUpdated":null}'),n={name:"tools.md"};function d(i,e,l,c,r,g){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="Tool-Catalog" tabindex="-1">Tool Catalog <a class="header-anchor" href="#Tool-Catalog" aria-label="Permalink to &quot;Tool Catalog {#Tool-Catalog}&quot;">​</a></h1><p>Kaimon exposes 49 MCP tools on its default surface, organized into the categories below (plus a handful of advanced/infra tools gated off by default — enable them per project in <code>.kaimon/tools.json</code>). Each default tool is available to any MCP client (Claude Code, Claude Desktop, etc.) connected to a running Kaimon server.</p><p>Most tools accept an optional <code>session</code> parameter (8-character session key) for routing when multiple Julia processes are connected.</p><h2 id="Code-Execution" tabindex="-1">Code Execution <a class="header-anchor" href="#Code-Execution" aria-label="Permalink to &quot;Code Execution {#Code-Execution}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>ex</code></td><td style="text-align:right;">Evaluate Julia code in a persistent REPL. The user sees code in real-time.</td><td style="text-align:right;"><code>e</code> (the Julia code — <strong>required</strong>; the parameter is <code>e</code>, not <code>code</code>), <code>q</code> (quiet, default true), <code>s</code> (silent), <code>max_output</code>, <code>ses</code> (session)</td></tr><tr><td style="text-align:right;"><code>manage_repl</code></td><td style="text-align:right;">Restart or shut down a Julia session. Restart preserves the session key.</td><td style="text-align:right;"><code>command</code> (&quot;restart&quot; or &quot;shutdown&quot;), <code>session</code></td></tr></tbody></table><p><strong><code>ex</code> – Evaluate Julia code</strong></p><p>The primary tool for interacting with Julia. By default, <code>q=true</code> suppresses return values to save tokens. Use <code>q=false</code> when you need the computed result.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ex(e=&quot;using LinearAlgebra; eigvals([1 2; 3 4])&quot;, q=false)</span></span>
<span class="line"><span># =&gt; 2-element Vector{Float64}: -0.3722..., 5.3722...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ex(e=&quot;x = rand(100, 100); size(x)&quot;)</span></span>
<span class="line"><span># (quiet mode -- return value suppressed, but code runs)</span></span></code></pre></div><h2 id="introspection" tabindex="-1">Introspection <a class="header-anchor" href="#introspection" aria-label="Permalink to &quot;Introspection&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>investigate_environment</code></td><td style="text-align:right;">Show pwd, active project, packages, dev packages, and Revise status.</td><td style="text-align:right;"><code>session</code></td></tr><tr><td style="text-align:right;"><code>search_methods</code></td><td style="text-align:right;">Find all methods of a function, or methods accepting a given type.</td><td style="text-align:right;"><code>query</code> (function or type name), <code>session</code></td></tr><tr><td style="text-align:right;"><code>type_info</code></td><td style="text-align:right;">Get type hierarchy, fields, parameters, mutability, and subtypes.</td><td style="text-align:right;"><code>type_expr</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>list_names</code></td><td style="text-align:right;">List exported (or all) names in a module.</td><td style="text-align:right;"><code>module_name</code>, <code>all</code> (bool), <code>session</code></td></tr><tr><td style="text-align:right;"><code>workspace_symbols</code></td><td style="text-align:right;">Search for symbols across all loaded modules by name.</td><td style="text-align:right;"><code>query</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>document_symbols</code></td><td style="text-align:right;">List functions, structs, macros, and constants in a file via AST parsing. No session required.</td><td style="text-align:right;"><code>file_path</code></td></tr><tr><td style="text-align:right;"><code>macro_expand</code></td><td style="text-align:right;">Expand a macro expression to see the generated code.</td><td style="text-align:right;"><code>expression</code>, <code>session</code></td></tr></tbody></table><p><strong><code>investigate_environment</code> – Orient yourself</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>investigate_environment()</span></span>
<span class="line"><span># =&gt; Project: MyApp v0.2.1</span></span>
<span class="line"><span>#    Path: /home/user/MyApp</span></span>
<span class="line"><span>#    pwd: /home/user/MyApp</span></span>
<span class="line"><span>#    Dev packages:</span></span>
<span class="line"><span>#      Kaimon v0.8.0 =&gt; ~/.julia/dev/Kaimon</span></span>
<span class="line"><span>#    Revise: active</span></span></code></pre></div><p><strong><code>search_methods</code> – Discover available methods</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>search_methods(query=&quot;sort&quot;)</span></span>
<span class="line"><span># =&gt; Methods for sort:</span></span>
<span class="line"><span>#    sort(v::AbstractVector; ...) @ Base sort.jl:1489</span></span>
<span class="line"><span>#    ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>search_methods(query=&quot;AbstractString&quot;)</span></span>
<span class="line"><span># =&gt; Methods with argument type AbstractString:</span></span>
<span class="line"><span>#    ...(all methods that accept AbstractString)...</span></span></code></pre></div><h2 id="Code-Analysis" tabindex="-1">Code Analysis <a class="header-anchor" href="#Code-Analysis" aria-label="Permalink to &quot;Code Analysis {#Code-Analysis}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>code_lowered</code></td><td style="text-align:right;">Show lowered (desugared) IR for a function.</td><td style="text-align:right;"><code>function_expr</code>, <code>types</code> (e.g. <code>&quot;(Float64,)&quot;</code>), <code>session</code></td></tr><tr><td style="text-align:right;"><code>code_typed</code></td><td style="text-align:right;">Show type-inferred IR for debugging type stability.</td><td style="text-align:right;"><code>function_expr</code>, <code>types</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>format_code</code></td><td style="text-align:right;">Format Julia source files using JuliaFormatter.jl.</td><td style="text-align:right;"><code>path</code> (file or directory), <code>overwrite</code>, <code>verbose</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>lint_package</code></td><td style="text-align:right;">Run Aqua.jl quality assurance tests on a package.</td><td style="text-align:right;"><code>package_name</code> (defaults to current project), <code>session</code></td></tr></tbody></table><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>goto_definition</code></td><td style="text-align:right;">Find where a symbol is defined. Uses Julia reflection (<code>methods</code>/<code>functionloc</code>/<code>pathof</code>) with a file-grep fallback.</td><td style="text-align:right;"><code>file_path</code>, <code>line</code>, <code>column</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>navigate_to_file</code></td><td style="text-align:right;">Open a file at a specific line and column in VS Code.</td><td style="text-align:right;"><code>file_path</code>, <code>line</code>, <code>column</code></td></tr></tbody></table><h2 id="VS-Code-Integration" tabindex="-1">VS Code Integration <a class="header-anchor" href="#VS-Code-Integration" aria-label="Permalink to &quot;VS Code Integration {#VS-Code-Integration}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>execute_vscode_command</code></td><td style="text-align:right;">Run any allowed VS Code command via the Remote Control extension.</td><td style="text-align:right;"><code>command</code>, <code>args</code>, <code>wait_for_response</code>, <code>timeout</code></td></tr><tr><td style="text-align:right;"><code>list_vscode_commands</code></td><td style="text-align:right;">List all commands configured in <code>.vscode/settings.json</code> as allowed.</td><td style="text-align:right;">(none)</td></tr></tbody></table><h2 id="Debugging-Infiltrator.jl" tabindex="-1">Debugging (Infiltrator.jl) <a class="header-anchor" href="#Debugging-Infiltrator.jl" aria-label="Permalink to &quot;Debugging (Infiltrator.jl) {#Debugging-Infiltrator.jl}&quot;">​</a></h2><p>Kaimon integrates with Infiltrator.jl for interactive breakpoint debugging. When a session hits <code>@infiltrate</code>, execution pauses and you can inspect locals and eval expressions in the breakpoint scope.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>debug_ctrl</code></td><td style="text-align:right;">Check breakpoint status or resume execution.</td><td style="text-align:right;"><code>action</code> (&quot;status&quot; or &quot;continue&quot;), <code>session</code></td></tr><tr><td style="text-align:right;"><code>debug_eval</code></td><td style="text-align:right;">Evaluate an expression in the context of a paused breakpoint.</td><td style="text-align:right;"><code>expression</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>debug_exfiltrate</code></td><td style="text-align:right;">Evaluate code containing <code>@exfiltrate</code> to capture local variables.</td><td style="text-align:right;"><code>code</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>debug_safehouse</code></td><td style="text-align:right;">Inspect or clear variables captured by <code>@exfiltrate</code>.</td><td style="text-align:right;"><code>action</code> (&quot;inspect&quot;/&quot;clear&quot;), <code>expression</code> (optional), <code>session</code></td></tr></tbody></table><h2 id="Package-Management" tabindex="-1">Package Management <a class="header-anchor" href="#Package-Management" aria-label="Permalink to &quot;Package Management {#Package-Management}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>pkg_add</code></td><td style="text-align:right;">Add packages to the current environment. Modifies <code>Project.toml</code>.</td><td style="text-align:right;"><code>packages</code> (array of names), <code>session</code></td></tr><tr><td style="text-align:right;"><code>pkg_rm</code></td><td style="text-align:right;">Remove packages from the current environment.</td><td style="text-align:right;"><code>packages</code> (array of names), <code>session</code></td></tr></tbody></table><h2 id="Testing-and-Profiling" tabindex="-1">Testing and Profiling <a class="header-anchor" href="#Testing-and-Profiling" aria-label="Permalink to &quot;Testing and Profiling {#Testing-and-Profiling}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>run_tests</code></td><td style="text-align:right;">Run project tests in a subprocess. Supports pattern filtering and coverage.</td><td style="text-align:right;"><code>pattern</code> (ReTest regex), <code>coverage</code>, <code>verbose</code>, <code>project_path</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>profile_code</code></td><td style="text-align:right;">Profile Julia code to identify performance bottlenecks. Uses <code>@profile</code> with flat output.</td><td style="text-align:right;"><code>code</code>, <code>session</code></td></tr><tr><td style="text-align:right;"><code>stress_test</code></td><td style="text-align:right;">Spawn concurrent simulated MCP agents to stress-test a session.</td><td style="text-align:right;"><code>code</code>, <code>num_agents</code>, <code>stagger</code>, <code>timeout</code>, <code>session</code></td></tr></tbody></table><p><strong><code>run_tests</code> – Run filtered tests</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>run_tests(pattern=&quot;security&quot;)</span></span>
<span class="line"><span># Runs only tests matching &quot;security&quot;</span></span>
<span class="line"><span># =&gt; Test Summary: ...</span></span>
<span class="line"><span>#    2 passed, 0 failed</span></span>
<span class="line"><span></span></span>
<span class="line"><span>run_tests(coverage=true)</span></span>
<span class="line"><span># Runs all tests with coverage collection</span></span>
<span class="line"><span></span></span>
<span class="line"><span>run_tests(project_path=&quot;/path/to/MyPackage.jl&quot;)</span></span>
<span class="line"><span># Run tests for a project without a gate session</span></span></code></pre></div><p>Provide <code>project_path</code> (absolute path to the project) or <code>session</code> to identify the project. If neither is given and only one session is connected, that session&#39;s project is used. The test runner handles both <code>test/Project.toml</code> environments and legacy <code>[extras]/[targets]</code> layouts automatically.</p><h2 id="Code-Search" tabindex="-1">Code Search <a class="header-anchor" href="#Code-Search" aria-label="Permalink to &quot;Code Search {#Code-Search}&quot;">​</a></h2><p><code>search_code</code> (by meaning) requires <a href="https://qdrant.tech/" target="_blank" rel="noreferrer">Qdrant</a> running locally and <a href="https://ollama.ai/" target="_blank" rel="noreferrer">Ollama</a> for embeddings (default model <code>qwen3-embedding:0.6b</code>); its lexical arm and <code>grep_code</code> work with no external services. The indexing/admin tools below feed <code>search_code</code>.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>search_code</code></td><td style="text-align:right;">Find code by MEANING – semantic (vector) search with a light lexical boost, fused and ranked. Describe a concept or behaviour; for an exact symbol or pattern use <code>grep_code</code> instead.</td><td style="text-align:right;"><code>query</code>, <code>mode</code> (&quot;hybrid&quot;/&quot;semantic&quot;/&quot;lexical&quot;), <code>format</code> (&quot;text&quot;/&quot;structured&quot;), <code>filters</code>, <code>collection</code>, <code>cross_project</code>, <code>limit</code>, <code>chunk_type</code> (&quot;all&quot;/&quot;definitions&quot;/&quot;windows&quot;), <code>embedding_model</code></td></tr><tr><td style="text-align:right;"><code>grep_code</code></td><td style="text-align:right;">Find an EXACT pattern/regex over the live working tree – repo-scoped, <code>.gitignore</code>-aware, and returns each hit&#39;s enclosing function/struct. The &quot;better grep than grep&quot;.</td><td style="text-align:right;"><code>pattern</code>, <code>path</code>/<code>file</code>/<code>glob</code> (scope), <code>query</code> (optional NL file-ranking), <code>ignore_case</code>, <code>word</code>, <code>fixed</code>, <code>no_ignore</code>, <code>context</code>, <code>limit</code></td></tr><tr><td style="text-align:right;"><code>qdrant_index_project</code></td><td style="text-align:right;">Index a project&#39;s source files into a Qdrant collection.</td><td style="text-align:right;"><code>project_path</code>, <code>collection</code>, <code>recreate</code>, <code>extra_dirs</code>, <code>extensions</code></td></tr><tr><td style="text-align:right;"><code>qdrant_sync_index</code></td><td style="text-align:right;">Incrementally sync an index – reindex changed files, remove deleted ones.</td><td style="text-align:right;"><code>project_path</code>, <code>collection</code>, <code>verbose</code></td></tr><tr><td style="text-align:right;"><code>qdrant_reindex_file</code></td><td style="text-align:right;">Re-index a single file (delete old chunks, index fresh).</td><td style="text-align:right;"><code>file_path</code>, <code>collection</code>, <code>project_path</code>, <code>verbose</code></td></tr><tr><td style="text-align:right;"><code>qdrant_list_collections</code></td><td style="text-align:right;">List all available Qdrant collections.</td><td style="text-align:right;">(none)</td></tr></tbody></table><p><code>search_code</code> and <code>grep_code</code> are the two ways to find code, and both beat shell <code>grep</code>/<code>find</code> (repo-scoped, <code>.gitignore</code>-aware, enclosing-symbol enrichment): use <code>search_code</code> when you can only <em>describe</em> what the code does, and <code>grep_code</code> when you know the literal text or a regex. <code>search_code</code> auto-tunes how much its lexical arm counts from the <em>shape</em> of the query (a natural-language sentence leans almost fully semantic; a quoted phrase, boolean, or bare symbol leans lexical), so just type what you mean. <code>format=&quot;structured&quot;</code> returns a JSON array of hits (<code>{point_id, name, file, type, start_line, end_line, text, snippet, sources, score}</code>) instead of the ranked text – for programmatic use; <code>filters={field:[vals]}</code> restricts to chunks carrying matching <code>metadata</code>. <code>grep_code</code> respects <code>.gitignore</code> by default; pass <code>no_ignore=true</code> to also grep logs and generated/hidden files. The raw vector-DB admin tools (<code>qdrant_collection_info</code>/<code>_exists</code>/<code>browse</code>/<code>create</code>/<code>delete_collection</code>, <code>qdrant_upsert</code>/<code>delete_points</code>, <code>qdrant_ensure_fts_coverage</code>) are gated off the default surface – enable them in <code>.kaimon/tools.json</code> if needed.</p><p><strong><code>search_code</code> – Find code by meaning</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>search_code(query=&quot;function that handles HTTP routing&quot;)</span></span>
<span class="line"><span># =&gt; [1 0.89] handle_request(req::Request) @ src/server.jl:L42-68 (function)</span></span>
<span class="line"><span>#    [2 0.81] route(path::String, handler) @ src/router.jl:L15-30 (function)</span></span>
<span class="line"><span>#    ...</span></span></code></pre></div><p><strong><code>grep_code</code> – Find an exact pattern</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>grep_code(pattern=&quot;_eval_with_capture&quot;)</span></span>
<span class="line"><span># =&gt; src/gate_stream.jl:L224  _eval_with_capture  function _eval_with_capture(...)</span></span>
<span class="line"><span>#    src/gate_eval.jl:L88     handle_eval         out = _eval_with_capture(code)</span></span>
<span class="line"><span>#    ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>grep_code(pattern=&quot;TODO|FIXME&quot;, glob=[&quot;src/**/*.jl&quot;])   # scope with a glob</span></span>
<span class="line"><span>grep_code(pattern=&quot;set_bind&quot;, query=&quot;apply a browser value change to a cell&quot;)  # NL-rank the matching files</span></span></code></pre></div><h2 id="Session-Management" tabindex="-1">Session Management <a class="header-anchor" href="#Session-Management" aria-label="Permalink to &quot;Session Management {#Session-Management}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>start_session</code></td><td style="text-align:right;">Spawn a managed Julia session for an allowed project. Call with no arguments to list available projects.</td><td style="text-align:right;"><code>project_path</code>, <code>name</code></td></tr><tr><td style="text-align:right;"><code>check_eval</code></td><td style="text-align:right;">Check status of a previous <code>ex()</code> evaluation by its eval ID. Returns status, elapsed time, and result preview.</td><td style="text-align:right;"><code>eval_id</code></td></tr><tr><td style="text-align:right;"><code>extension_info</code></td><td style="text-align:right;">List loaded extensions and their tools. With <code>name</code>, show detailed tool docs and parameter schemas.</td><td style="text-align:right;"><code>name</code> (optional)</td></tr></tbody></table><p><strong><code>start_session</code> – Spawn a project session</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>start_session()</span></span>
<span class="line"><span># =&gt; Lists all allowed projects and their status</span></span>
<span class="line"><span></span></span>
<span class="line"><span>start_session(project_path=&quot;/path/to/MyProject&quot;)</span></span>
<span class="line"><span># =&gt; &quot;Session started. Session key: a3f8b2c1&quot;</span></span></code></pre></div><p>The project must be in the allowed-projects list (<code>~/.config/kaimon/projects.json</code>). See <a href="/Kaimon.jl/dev/sessions#managed-sessions">Sessions</a> for details.</p><p><strong><code>check_eval</code> – Poll a long-running evaluation</strong></p><p>Every <code>ex()</code> call returns an eval ID as a structured JSON field <code>{&quot;eval_id&quot;: &quot;XXXXXXXX&quot;}</code> in its first progress notification. Use <code>check_eval</code> to poll for completion:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>check_eval(eval_id=&quot;abc12345&quot;)</span></span>
<span class="line"><span># =&gt; status: completed, elapsed: 12.3s, result: &quot;42&quot;</span></span></code></pre></div><h2 id="information" tabindex="-1">Information <a class="header-anchor" href="#information" aria-label="Permalink to &quot;Information&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Description</th><th style="text-align:right;">Key Parameters</th></tr></thead><tbody><tr><td style="text-align:right;"><code>ping</code></td><td style="text-align:right;">Health check. Returns server status, Revise status, and connected sessions.</td><td style="text-align:right;">(none)</td></tr><tr><td style="text-align:right;"><code>usage_instructions</code></td><td style="text-align:right;">Get Julia REPL usage instructions and best practices for AI agents.</td><td style="text-align:right;">(none)</td></tr><tr><td style="text-align:right;"><code>usage_quiz</code></td><td style="text-align:right;">Self-graded quiz on Kaimon usage patterns. Tests understanding of the shared REPL model.</td><td style="text-align:right;"><code>show_sols</code> (bool)</td></tr><tr><td style="text-align:right;"><code>tool_help</code></td><td style="text-align:right;">Get detailed help and examples for any specific tool.</td><td style="text-align:right;"><code>tool_name</code>, <code>extended</code> (bool)</td></tr></tbody></table>`,48)])])}const u=t(n,[["render",d]]);export{h as __pageData,u as default};
